SELECT title, media_type, language
FROM works
WHERE country = 'United States' AND year BETWEEN 1980 AND 1990 AND rating > 8;

SELECT AVG(rating)
FROM works
WHERE director = 'Ridley Scott';

SELECT title, author, year
FROM works
WHERE rating > 8;

SELECT title 
FROM works 
WHERE genre = 'novel' AND rating = (SELECT MAX(rating) FROM works WHERE genre = 'novel');

SELECT tech_name FROM technologies WHERE tech_id = (
  SELECT MIN(tech_id) FROM work_technologies WHERE work_id IN (
    SELECT work_id FROM works WHERE title LIKE "%Space%"
  )
);

SELECT title AS name FROM works WHERE year < 2000
UNION
SELECT tech_name AS name FROM technologies WHERE first_appearance < 2000;

SELECT t.tech_name
FROM technologies t
JOIN work_technologies wt ON t.tech_id = wt.tech_id
WHERE wt.importance = (
    SELECT MAX(importance) FROM work_technologies
);
